import{_ as a,o as i,c as e,a2 as o}from"./chunks/framework.VshInwhI.js";const u=JSON.parse('{"title":"弹框与抽屉 UI 规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/frontend/11-dialog-drawer.md","filePath":"mango-pmo/rules/frontend/11-dialog-drawer.md"}'),r={name:"mango-pmo/rules/frontend/11-dialog-drawer.md"};function t(n,l,d,h,s,_){return i(),e("div",null,[...l[0]||(l[0]=[o('<h1 id="弹框与抽屉-ui-规范" tabindex="-1">弹框与抽屉 UI 规范 <a class="header-anchor" href="#弹框与抽屉-ui-规范" aria-label="Permalink to &quot;弹框与抽屉 UI 规范&quot;">​</a></h1><h2 id="_1-使用场景" tabindex="-1">1. 使用场景 <a class="header-anchor" href="#_1-使用场景" aria-label="Permalink to &quot;1. 使用场景&quot;">​</a></h2><ol><li>短表单和确认操作使用弹框。</li><li>字段较多、需要上下文参照或分组编辑时使用抽屉或独立页面。</li><li>复杂业务判断、长流程、多模块编辑不放进小弹框。</li></ol><h2 id="_2-弹框规则" tabindex="-1">2. 弹框规则 <a class="header-anchor" href="#_2-弹框规则" aria-label="Permalink to &quot;2. 弹框规则&quot;">​</a></h2><ol><li>弹框标题必须明确表达动作和对象。</li><li>弹框内容按业务分组，不按接口字段顺序堆叠。</li><li>弹框 footer 操作位置保持一致。</li><li>确认按钮必须有提交 loading。</li><li>提交中禁止重复提交。</li><li>关闭未保存内容前必须提醒确认。</li></ol><h2 id="_3-抽屉规则" tabindex="-1">3. 抽屉规则 <a class="header-anchor" href="#_3-抽屉规则" aria-label="Permalink to &quot;3. 抽屉规则&quot;">​</a></h2><ol><li>抽屉适合字段多、上下文强、需要分组编辑的场景。</li><li>抽屉内仍需按业务模块分组。</li><li>抽屉操作区保持稳定。</li><li>不得把完整复杂页面硬塞进抽屉。</li></ol><h2 id="_4-删除确认" tabindex="-1">4. 删除确认 <a class="header-anchor" href="#_4-删除确认" aria-label="Permalink to &quot;4. 删除确认&quot;">​</a></h2><ol><li>删除、移除、清空等危险操作必须二次确认。</li><li>删除确认必须说明影响范围。</li><li>删除确认按钮使用 <code>danger</code>。</li><li>删除确认按钮文案应明确为“确认删除”。</li><li>禁止只写“确定”作为危险操作确认文案。</li></ol><h2 id="_5-检查清单" tabindex="-1">5. 检查清单 <a class="header-anchor" href="#_5-检查清单" aria-label="Permalink to &quot;5. 检查清单&quot;">​</a></h2><ol><li>弹框/抽屉是否适合当前任务复杂度。</li><li>标题是否明确表达动作和对象。</li><li>字段是否按业务分组。</li><li>确认按钮是否有 loading。</li><li>未保存关闭是否有确认。</li><li>危险操作是否说明影响范围并使用 <code>danger</code>。</li></ol>',11)])])}const m=a(r,[["render",t]]);export{u as __pageData,m as default};
